```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ServerShipmentService : IShipmentService
{
    private readonly ApplicationDbContext _db;

    public ServerShipmentService(ApplicationDbContext db) => _db = db;

    public async Task<List<Shipment>> GetAllShipmentsAsync(string? statusFilter = null, string? searchTerm = null)
    {
        var query = _db.Shipments.AsQueryable();

        if (!string.IsNullOrEmpty(statusFilter) && Enum.TryParse<ShipmentStatus>(statusFilter, true, out var status))
            query = query.Where(s => s.Status == status);

        if (!string.IsNullOrEmpty(searchTerm))
            query = query.Where(s =>
                s.TrackingNumber.Contains(searchTerm) ||
                s.Destination.Contains(searchTerm) ||
                s.RecipientName.Contains(searchTerm) ||
                s.SenderName.Contains(searchTerm));

        return await query.OrderByDescending(s => s.ShippedDate).ToListAsync();
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        return await _db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
    }

    public async Task<Shipment?> GetShipmentByIdAsync(int id)
    {
        return await _db.Shipments.FindAsync(id);
    }

    public async Task UpdateShipmentStatusAsync(int id, ShipmentStatus newStatus)
    {
        var shipment = await _db.Shipments.FindAsync(id);
        if (shipment is not null)
        {
            shipment.Status = newStatus;
            if (newStatus == ShipmentStatus.Delivered)
                shipment.ActualDelivery = DateTime.UtcNow;
            await _db.SaveChangesAsync();
        }
    }
}
```

