```csharp
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("", async (IShipmentService service, string? status, string? search) =>
            Results.Ok(await service.GetAllShipmentsAsync(status, search)));

        group.MapGet("{id:int}", async (IShipmentService service, int id) =>
        {
            var shipment = await service.GetShipmentByIdAsync(id);
            return shipment is not null ? Results.Ok(shipment) : Results.NotFound();
        });

        group.MapGet("track/{trackingNumber}", async (IShipmentService service, string trackingNumber) =>
        {
            var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
            return shipment is not null ? Results.Ok(shipment) : Results.NotFound();
        }).AllowAnonymous();

        group.MapPut("{id:int}/status", async (IShipmentService service, int id, ShipmentStatus newStatus) =>
        {
            await service.UpdateShipmentStatusAsync(id, newStatus);
            return Results.NoContent();
        });
    }
}
```

Note: The track endpoint is AllowAnonymous so customers can look up shipments without signing in. The rest requires auth.

