+@page "/shipments"
+@using Microsoft.AspNetCore.Authorization
+@using ShipmentTracker.Client.Models
+@using ShipmentTracker.Client.Services
+@attribute [Authorize]
+@inject IShipmentService ShipmentService
+
+<PageTitle>Shipments - ShipmentTracker</PageTitle>
+
+<h1>Shipments</h1>
+
+<div class="row mb-3">
+    <div class="col-md-4">
+        <input type="text" class="form-control" placeholder="Search by tracking #, destination, or name..."
+               @bind="searchTerm" @bind:event="oninput" @bind:after="LoadShipments" />
+    </div>
+    <div class="col-md-3">
+        <select class="form-select" @bind="statusFilter" @bind:after="LoadShipments">
+            <option value="">All Statuses</option>
+            @foreach (var status in Enum.GetValues<ShipmentStatus>())
+            {
+                <option value="@status">@status</option>
+            }
+        </select>
+    </div>
+    <div class="col-md-2">
+        <button class="btn btn-outline-secondary" @onclick="ClearFilters">Clear Filters</button>
+    </div>
+</div>
+
+@if (shipments is null)
+{
+    <p><em>Loading shipments...</em></p>
+}
+else if (shipments.Count == 0)
+{
+    <div class="alert alert-info">No shipments match your criteria.</div>
+}
+else
+{
+    <div class="table-responsive">
+        <table class="table table-striped table-hover">
+            <thead class="table-dark">
+                <tr>
+                    <th>Tracking #</th>
+                    <th>Origin</th>
+                    <th>Destination</th>
+                    <th>Recipient</th>
+                    <th>Status</th>
+                    <th>Shipped</th>
+                    <th>Est. Delivery</th>
+                    <th>Weight (kg)</th>
+                    <th>Actions</th>
+                </tr>
+            </thead>
+            <tbody>
+                @foreach (var shipment in shipments)
+                {
+                    <tr>
+                        <td><strong>@shipment.TrackingNumber</strong></td>
+                        <td>@shipment.Origin</td>
+                        <td>@shipment.Destination</td>
+                        <td>@shipment.RecipientName</td>
+                        <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
+                        <td>@shipment.ShippedDate.ToString("MMM dd")</td>
+                        <td>@shipment.EstimatedDelivery.ToString("MMM dd")</td>
+                        <td>@shipment.WeightKg</td>
+                        <td>
+                            @if (editingShipmentId == shipment.Id)
+                            {
+                                <div class="d-flex gap-1">
+                                    <select class="form-select form-select-sm" style="width: auto;" @bind="newStatus">
+                                        @foreach (var s in Enum.GetValues<ShipmentStatus>())
+                                        {
+                                            <option value="@s">@s</option>
+                                        }
+                                    </select>
+                                    <button class="btn btn-sm btn-success" @onclick="() => SaveStatus(shipment.Id)">Save</button>
+                                    <button class="btn btn-sm btn-secondary" @onclick="CancelEdit">Cancel</button>
+                                </div>
+                            }
+                            else
+                            {
+                                <button class="btn btn-sm btn-outline-primary" @onclick="() => StartEdit(shipment)">
+                                    Update Status
+                                </button>
+                            }
+                        </td>
+                    </tr>
+                }
+            </tbody>
+        </table>
+    </div>
+    <p class="text-muted">Showing @shipments.Count shipment(s)</p>
+}
+
+@code {
+    private List<Shipment>? shipments;
+    private string searchTerm = "";
+    private string statusFilter = "";
+    private int? editingShipmentId;
+    private ShipmentStatus newStatus;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadShipments();
+    }
+
+    private async Task LoadShipments()
+    {
+        shipments = await ShipmentService.GetAllShipmentsAsync(statusFilter, searchTerm);
+    }
+
+    private void StartEdit(Shipment shipment)
+    {
+        editingShipmentId = shipment.Id;
+        newStatus = shipment.Status;
+    }
+
+    private void CancelEdit()
+    {
+        editingShipmentId = null;
+    }
+
+    private async Task SaveStatus(int id)
+    {
+        await ShipmentService.UpdateShipmentStatusAsync(id, newStatus);
+        editingShipmentId = null;
+        await LoadShipments();
+    }
+
+    private async Task ClearFilters()
+    {
+        searchTerm = "";
+        statusFilter = "";
+        await LoadShipments();
+    }
+
+    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
+    {
+        ShipmentStatus.Delivered => "bg-success",
+        ShipmentStatus.InTransit => "bg-primary",
+        ShipmentStatus.OutForDelivery => "bg-info text-dark",
+        ShipmentStatus.Delayed => "bg-warning text-dark",
+        ShipmentStatus.Returned => "bg-danger",
+        ShipmentStatus.Pending => "bg-secondary",
+        ShipmentStatus.PickedUp => "bg-primary",
+        _ => "bg-secondary"
+    };
+}
+

