@page "/"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService
@inject NavigationManager Navigation

<PageTitle>ShipmentTracker - Home</PageTitle>

<h1>Shipment Tracker</h1>
<p class="lead">Track your shipments in real time. Enter your tracking number below to get started.</p>

<div class="row mt-4">
    <div class="col-md-8">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Track a Shipment</h5>
                <div class="input-group">
                    <input type="text" class="form-control" placeholder="Enter tracking number (e.g., TRK-20260501-001)"
                           @bind="trackingNumber" @bind:event="oninput"
                           @onkeydown="HandleKeyDown" />
                    <button class="btn btn-primary" @onclick="TrackShipment" disabled="@string.IsNullOrWhiteSpace(trackingNumber)">
                        Track
                    </button>
                </div>

                @if (searchPerformed)
                {
                    @if (trackedShipment is not null)
                    {
                        <div class="mt-3 alert alert-info">
                            <h6>@trackedShipment.TrackingNumber</h6>
                            <p class="mb-1"><strong>Status:</strong> <span class="badge @GetStatusBadgeClass(trackedShipment.Status)">@trackedShipment.Status</span></p>
                            <p class="mb-1"><strong>From:</strong> @trackedShipment.Origin <strong>→</strong> @trackedShipment.Destination</p>
                            <p class="mb-1"><strong>Estimated Delivery:</strong> @trackedShipment.EstimatedDelivery.ToString("MMM dd, yyyy")</p>
                            @if (trackedShipment.ActualDelivery.HasValue)
                            {
                                <p class="mb-0"><strong>Delivered:</strong> @trackedShipment.ActualDelivery.Value.ToString("MMM dd, yyyy")</p>
                            }
                        </div>
                    }
                    else
                    {
                        <div class="mt-3 alert alert-warning">
                            No shipment found with tracking number "<strong>@searchedNumber</strong>".
                        </div>
                    }
                }
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Dispatcher?</h5>
                <p class="card-text">Sign in to view and manage all shipments.</p>
                <AuthorizeView>
                    <Authorized>
                        <a href="/shipments" class="btn btn-outline-primary">View Shipments</a>
                    </Authorized>
                    <NotAuthorized>
                        <a href="Account/Login" class="btn btn-outline-primary">Sign In</a>
                    </NotAuthorized>
                </AuthorizeView>
            </div>
        </div>
    </div>
</div>

@code {
    private string trackingNumber = "";
    private string searchedNumber = "";
    private Shipment? trackedShipment;
    private bool searchPerformed;

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;
        searchedNumber = trackingNumber.Trim();
        trackedShipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchedNumber);
        searchPerformed = true;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info text-dark",
        ShipmentStatus.Delayed => "bg-warning text-dark",
        ShipmentStatus.Returned => "bg-danger",
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-primary",
        _ => "bg-secondary"
    };
}

